const diffResponse = $input.all()[0];
const codeDiff = diffResponse.json.data || diffResponse.json.body || diffResponse.json;
const diffText = typeof codeDiff === 'string' ? codeDiff : JSON.stringify(codeDiff);

const prData   = $('GitHub PR Trigger').item.json;
const prTitle  = prData.pull_request?.title || 'Unknown PR';
const prNumber = prData.number;
const prAuthor = prData.pull_request?.user?.login || 'Unknown';
const repoOwner    = prData.repository?.owner?.login || 'Unknown';
const repoNameOnly = prData.repository?.name || 'Unknown';
const prBody       = prData.pull_request?.body || '';
const baseBranch   = prData.pull_request?.base?.ref || 'main';
const headBranch   = prData.pull_request?.head?.ref || 'unknown';

const maxDiffLength = 10000;
const diff = diffText.length > maxDiffLength
  ? diffText.substring(0, maxDiffLength) + '\n... [TRUNCATED]'
  : diffText;

const header = [
  `PR #${prNumber}: "${prTitle}"`,
  `Author: @${prAuthor} | Branch: ${headBranch} → ${baseBranch}`,
  '',
].join('\n');

const diffBlock = ['```diff', diff, '```'].join('\n');

return [{
  json: {
    prNumber,
    prTitle,
    prAuthor,
    repoOwner,
    repoNameOnly,
    baseBranch,
    headBranch,
    // modelPrompts structure — each model gets a typed prompt + temperature number
    modelPrompts: {
      deepseek_r1: {
        temperature: 0.1,  // strictly typed number
        prompt: [
          '🔒 DEEPSEEK R1 — SECURITY AUDIT',
          header,
          'You are DeepSeek R1, a security-focused AI auditor. Hard-review this PR for:',
          '1. SQL/NoSQL/Command Injection  2. XSS/CSRF  3. Auth bypasses',
          '4. Hardcoded secrets  5. Vulnerable deps  6. Rate limiting gaps',
          '',
          diffBlock,
          '',
          'OUTPUT FORMAT:',
          'VERDICT: PASS | FAIL | BLOCK',
          'SEVERITY: Critical | High | Medium | Low | None',
          'VULNERABILITIES: - (list)',
          'RECOMMENDATIONS: - (list)',
          'SUMMARY: (one sentence)',
        ].join('\n'),
      },
      qwen3: {
        temperature: 0.2,  // strictly typed number
        prompt: [
          '🏗️ QWEN 3 — ARCHITECTURE REVIEW',
          header,
          'You are Qwen 3, a senior TypeScript/Next.js architect. Review for:',
          '1. Design patterns  2. Type safety  3. Performance (O-complexity)',
          '4. Redundant loops  5. Error handling  6. Test coverage',
          '',
          diffBlock,
          '',
          'OUTPUT FORMAT:',
          'VERDICT: APPROVE | REQUEST_CHANGES | NEEDS_DISCUSSION',
          'ARCHITECTURE_SCORE: (1-10)',
          'ISSUES: - (list with severity)',
          'IMPROVEMENTS: - (with code examples)',
          'SUMMARY: (one sentence)',
        ].join('\n'),
      },
      kimi_k2: {
        temperature: 0.2,  // strictly typed number
        prompt: [
          '<think>',
          '🎯 KIMI K2 — PRODUCT IMPACT ASSESSMENT',
          header,
          `PR Description: ${prBody.substring(0, 400)}`,
          '',
          'You are Kimi K2, product/UX specialist for the Apex African Futurism platform.',
          '1. Feature roadmap alignment  2. UX impact  3. Backward compat',
          '4. Edge cases  5. Accessibility  6. Mobile/responsive',
          '',
          diffBlock,
          '',
          'OUTPUT FORMAT:',
          'VERDICT: APPROVE | NEEDS_REVISION | NEEDS_DISCUSSION',
          'PRODUCT_ALIGNMENT: (1-10)',
          'UX_IMPACT: Positive | Neutral | Negative',
          'CONCERNS: - (list)',
          'RECOMMENDATIONS: - (list)',
          'SUMMARY: (one sentence)',
          '</think>',
        ].join('\n'),
      },
    },
  }
}];

const items = $input.all();
const models = [
  { id: 'deepseek-r1', label: 'DeepSeek R1 (Security)'   },
  { id: 'qwen3',       label: 'Qwen 3 (Architecture)'    },
  { id: 'kimi-k2',     label: 'Kimi K2 (Product)'        },
];
return items.map((item, i) => {
  const raw = item.json.response || item.json.choices?.[0]?.message?.content || '[no response]';
  const cleaned = raw
    .replace(/<think[\s\S]*?>[\s\S]*?<\/think>/gi, '')
    .replace(/<thinking>[\s\S]*?<\/thinking>/gi, '')
    .trim();
  return { json: {
    model_id:    models[i]?.id    || `model_${i}`,
    model_label: models[i]?.label || `Model ${i}`,
    response:    cleaned,
    word_count:  cleaned.split(/\s+/).length,
    timed_out:   cleaned.length < 10,
  }};
});

// ═══════════════════════════════════════════════════════════════════════════
// Score & Consensus — weighted scoring + DeepSeek hard-fail + fallback cascade
// Weights: DeepSeek×0.40 + Qwen×0.35 + Kimi×0.25
// ═══════════════════════════════════════════════════════════════════════════

const items    = $input.all();
const prepData = $('Prepare Prompts').item.json;

// ─── Confidence-based fallback cascade ───────────────────────────────────
// If ALL models timed out or returned errors → FALLBACK (safe default)
// If ONLY DeepSeek failed → use Qwen+Kimi scores, flag for human review
const allFailed    = items.every(i => i.json.timed_out);
const deepseekFailed = items.find(i => i.json.model_id === 'deepseek-r1')?.json?.timed_out;

if (allFailed) {
  return [{ json: {
    prNumber:     prepData.prNumber,
    prTitle:      prepData.prTitle,
    prAuthor:     prepData.prAuthor,
    repoOwner:    prepData.repoOwner,
    repoName:     prepData.repoNameOnly,
    finalVerdict: 'NEEDS_DISCUSSION',
    winner:       'Fallback (All Models Unavailable)',
    scores:       { deepseek: 0, qwen: 0, kimi: 0 },
    verdicts:     { deepseek: 'TIMEOUT', qwen: 'TIMEOUT', kimi: 'TIMEOUT' },
    final_review: `⚠️ **Apex Tri-Model Council — Fallback**\n\n**PR #${prepData.prNumber}: ${prepData.prTitle}**\n\nAll 3 models (DeepSeek R1, Qwen 3.5, Kimi K2) timed out or returned errors.\n\n**Action required:** Manual review by a human engineer before merge.\n\n*Reviewed by Apex Tri-Model Council — cascade triggered*`,
  }}];
}

// ─── Scoring weights ──────────────────────────────────────────────────────
const weights = { 'deepseek-r1': 0.40, 'qwen3.5': 0.35, 'kimi-k2': 0.25 };

function extractVerdict(text) {
  const m = text.match(/VERDICT:\s*(PASS|FAIL|BLOCK|APPROVE|REQUEST_CHANGES|NEEDS_DISCUSSION|NEEDS_REVISION)/i);
  if (!m) return 'NEEDS_REVIEW';
  const v = m[1].toUpperCase();
  if (v === 'PASS' || v === 'APPROVE') return 'APPROVE';
  if (v === 'FAIL' || v === 'BLOCK' || v === 'REQUEST_CHANGES') return 'REQUEST_CHANGES';
  return 'NEEDS_DISCUSSION';
}

function extractScore(text, model) {
  const t = text.toLowerCase();
  let score = 50;
  if (model === 'deepseek-r1') {
    if (t.includes('severity: critical') || t.includes('verdict: block')) return 15;
    if (t.includes('severity: high')     || t.includes('verdict: fail'))  return 38;
    if (t.includes('severity: medium'))  return 58;
    if (t.includes('severity: low')      || t.includes('verdict: pass'))  return 85;
    if (t.includes('no vulnerabilities')) return 95;
    if (t.includes('sql injection')) score -= 20;
    if (t.includes('xss'))           score -= 15;
  } else if (model === 'qwen3.5') {
    const m = t.match(/architecture_score[:\s]+(\d+)/);
    if (m) return Math.min(parseInt(m[1]) * 10, 100);
    if (t.includes('verdict: approve'))          score = 85;
    if (t.includes('verdict: request_changes'))  score = 42;
    if (t.includes('performance')) score += 5;
  } else if (model === 'kimi-k2') {
    const m = t.match(/product_alignment[:\s]+(\d+)/);
    if (m) return Math.min(parseInt(m[1]) * 10, 100);
    if (t.includes('ux_impact: positive')) score = 85;
    if (t.includes('ux_impact: negative')) score = 35;
    if (t.includes('verdict: approve'))    score = 78;
  }
  return Math.max(0, Math.min(100, score));
}

const scored = items.map(item => {
  const { model_id, model_label, response, timed_out } = item.json;
  const score   = timed_out ? 0 : extractScore(response, model_id);
  const verdict = timed_out ? (deepseekFailed && model_id === 'deepseek-r1' ? 'CASCADED_TO_PEERS' : 'TIMEOUT')
                             : extractVerdict(response);
  return { model_id, model_label, response, score, verdict, timed_out,
           weighted: score * (weights[model_id] || 0.33) };
});

// ─── DeepSeek hard-fail gate ──────────────────────────────────────────────
let winner = scored.reduce((a, b) => b.weighted > a.weighted ? b : a);
const ds      = scored.find(r => r.model_id === 'deepseek-r1');
const hardFail = !ds?.timed_out && ds?.verdict === 'REQUEST_CHANGES' && ds?.score < 50;

if (hardFail) {
  winner = ds;   // DeepSeek rejection is authoritative
}

// ─── Final verdict ────────────────────────────────────────────────────────
let finalVerdict = 'APPROVE';
if (hardFail) {
  finalVerdict = 'REQUEST_CHANGES';
} else {
  const vs = scored.map(r => r.verdict);
  if (vs.filter(v => v === 'REQUEST_CHANGES').length >= 2) finalVerdict = 'REQUEST_CHANGES';
  else if (vs.filter(v => v === 'NEEDS_DISCUSSION').length >= 2) finalVerdict = 'NEEDS_DISCUSSION';
  else if (deepseekFailed) finalVerdict = 'NEEDS_DISCUSSION';  // security check absent → flag
}

const icon = finalVerdict === 'APPROVE' ? '✅' : finalVerdict === 'REQUEST_CHANGES' ? '❌' : '⚠️';
const fallbackNote = deepseekFailed
  ? '\n> ⚠️ **Note:** DeepSeek R1 (Security) was unavailable. Security review cascaded to peer models. Human security review recommended.\n'
  : '';

const scoreTable = scored.map(s =>
  `| ${s.model_label} | ${s.score}/100 | ${s.verdict} | ${s.timed_out ? '⏱ timeout' : '✓'} |`
).join('\n');

const finalReview = [
  `${icon} **Apex Tri-Model Council — PR Review**`,
  `**PR #${prepData.prNumber}: ${prepData.prTitle}**`,
  `**Author:** @${prepData.prAuthor} | **Branch:** \`${prepData.headBranch}\` → \`${prepData.baseBranch}\``,
  fallbackNote,
  '---',
  '### 📊 Model Scores',
  '| Model | Score | Verdict | Status |',
  '|-------|-------|---------|--------|',
  scoreTable,
  '---',
  `### 🏆 Best Response: ${winner.model_label}`,
  '```',
  winner.response.substring(0, 2800) + (winner.response.length > 2800 ? '\n... [truncated]' : ''),
  '```',
  '---',
  `### ${icon} Final Verdict: **${finalVerdict}**`,
  '',
  '*Reviewed by Apex Tri-Model Council — DeepSeek R1 + Qwen 3.5 + Kimi K2 | Africa/Johannesburg*',
].join('\n');

return [{
  json: {
    prNumber:     prepData.prNumber,
    prTitle:      prepData.prTitle,
    prAuthor:     prepData.prAuthor,
    repoOwner:    prepData.repoOwner,
    repoName:     prepData.repoNameOnly,
    finalVerdict,
    winner:       winner.model_label,
    scores: { deepseek: scored[0]?.score || 0, qwen: scored[1]?.score || 0, kimi: scored[2]?.score || 0 },
    verdicts: { deepseek: scored[0]?.verdict, qwen: scored[1]?.verdict, kimi: scored[2]?.verdict },
    final_review: finalReview,
    hard_fail: hardFail,
    fallback_cascade: deepseekFailed || allFailed,
    all_responses: {
      deepseek: scored[0]?.response || '',
      qwen:     scored[1]?.response || '',
      kimi:     scored[2]?.response || '',
    },
  }
}];
